import React, { useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import { Card, Button, Container, Row, Col } from "react-bootstrap";

function Study({ decks, cards}) {
    const [flipped, setFlipped] = useState(false);
    let index = 0;
    let content, nextButton;

    const params = useParams();
    const deck = decks.find(item => item.id.toString() === params.deckId)

    // Test to be sure cards and deck are present.
    if (!deck || cards.length === 0) {
        return <h4>Loading...</h4>
    }
    // Flip the card.
    if (flipped) {
        content = cards[index].back;
        nextButton = <Button onClick={() => index += 1} className="m-1">Next</Button>;
    } else {
        content = cards[index].front;
        nextButton = null;
    }
    

    return(
        <div>
            <h1>Study: {deck.name}</h1>
            <Card>
                <Card.Body>
                    <Card.Title>
                        Card {index + 1} of {cards.length}
                    </Card.Title>
                    <Card.Text>
                        {content}
                    </Card.Text>
                    <Button onClick={() => setFlipped(!flipped)} variant="secondary" className="m-2">
                        Flip
                    </Button>
                        {nextButton}
                </Card.Body>
            </Card>
        </div>
    )
}

export default Study;
